\\"Similarity\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Prinsip Closure menjelaskan bahwa pengguna dapat memahami ikon meskipun …\\",\\"options\\":[\\"Ukurannya besar\\",\\"Berwarna kontras\\",\\"Detail visualnya tidak lengkap\\",\\"Dilengkapi teks\\"],\\"answer\\":\\"Detail visualnya tidak lengkap\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Breadcrumb navigation merupakan contoh penerapan prinsip Gestalt …\\",\\"options\\":[\\"Proximity\\",\\"Similarity\\",\\"Continuity\\",\\"Closure\\"],\\"answer\\":\\"Continuity\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Hick’s Law menyatakan bahwa waktu pengambilan keputusan akan …\\",\\"options\\":[\\"Berkurang jika informasi detail\\",\\"Bertambah seiring jumlah pilihan\\",\\"Tidak dipengaruhi jumlah opsi\\",\\"Bergantung pada ukuran tombol\\"],\\"answer\\":\\"Bertambah seiring jumlah pilihan\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Rumus Hick’s Law (T = b log₂(n + 1)) menunjukkan bahwa …\\",\\"options\\":[\\"Waktu respons linear terhadap jumlah pilihan\\",\\"Semakin banyak pilihan, waktu bertindak meningkat secara logaritmik\\",\\"Jumlah pilihan tidak berpengaruh signifikan\\",\\"Kecepatan dipengaruhi warna UI\\"],\\"answer\\":\\"Semakin banyak pilihan, waktu bertindak meningkat secara logaritmik\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Fitts’ Law menekankan pentingnya …\\",\\"options\\":[\\"Jumlah pilihan menu\\",\\"Konsistensi ikon\\",\\"Ukuran dan jarak target interaksi\\",\\"Urutan navigasi\\"],\\"answer\\":\\"Ukuran dan jarak target interaksi\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Jakob’s Law menyarankan desainer untuk …\\",\\"options\\":[\\"Menciptakan pola interaksi baru sepenuhnya\\",\\"Menghindari konvensi desain lama\\",\\"Menyesuaikan desain dengan sistem yang sudah dikenal pengguna\\",\\"Mengutamakan estetika dibanding fungsi\\"],\\"answer\\":\\"Menyesuaikan desain dengan sistem yang sudah dikenal pengguna\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Desain intuitif mengandalkan pengalaman dan persepsi pengg