ua fitur opsional\\"],\\"answer\\":\\"Pengguna tahu data yang dikumpulkan\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Prototype dalam Design Thinking bersifat …\\",\\"options\\":[\\"Final\\",\\"Mahal\\",\\"Cepat dan tidak harus sempurna\\",\\"Kompleks\\"],\\"answer\\":\\"Cepat dan tidak harus sempurna\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Focused immersion terjadi ketika pengguna …\\",\\"options\\":[\\"Menyelesaikan tugas cepat\\",\\"Terlibat penuh hingga lupa waktu\\",\\"Menghafal fitur\\",\\"Membaca dokumentasi\\"],\\"answer\\":\\"Terlibat penuh hingga lupa waktu\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Tujuan utama desain etis adalah …\\",\\"options\\":[\\"Profit\\",\\"Perlindungan hak dan kepercayaan pengguna\\",\\"Efisiensi teknis\\",\\"Standarisasi UI\\"],\\"answer\\":\\"Perlindungan hak dan kepercayaan pengguna\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Usability hanya berkaitan dengan teknologi.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Empathize merupakan fondasi Design Thinking.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"True\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Joy dan Curiosity memengaruhi niat penggunaan sistem.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"True\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Gesture interaction selalu lebih baik dari touch.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Cognitive load tinggi meningkatkan kenyamanan pengguna.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"AI dalam UI/UX hanya memengaruhi aspek visual.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Emotional Design berkontribusi pada pengalaman menyenangkan.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"True\\",\\"type\\":\\"TF\\"},{\\"question\\":\\"Multimodal interfa