options\\":[\\"Mengukur waktu penyelesaian tugas\\",\\"Memahami proses berpikir pengguna secara langsung\\",\\"Menghitung jumlah error sistem\\",\\"Menguji performa server\\"],\\"answer\\":\\"Memahami proses berpikir pengguna secara langsung\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Salah satu kelemahan Think-Aloud Protocol adalah\\",\\"options\\":[\\"Tidak menghasilkan data kualitatif\\",\\"Membutuhkan perangkat mahal\\",\\"Dapat memengaruhi perilaku alami pengguna\\",\\"Tidak relevan dalam IMK\\"],\\"answer\\":\\"Dapat memengaruhi perilaku alami pengguna\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Usability testing yang dilakukan tanpa fasilitator disebut\\",\\"options\\":[\\"Moderated testing\\",\\"Remote testing\\",\\"Controlled testing\\",\\"Unmoderated testing\\"],\\"answer\\":\\"Unmoderated testing\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Data berupa waktu penyelesaian tugas dan jumlah kesalahan termasuk data\\",\\"options\\":[\\"Deskriptif\\",\\"Kualitatif\\",\\"Kuantitatif\\",\\"Eksploratif\\"],\\"answer\\":\\"Kuantitatif\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Prioritas perbaikan dalam analisis hasil evaluasi usability ditentukan berdasarkan\\",\\"options\\":[\\"Preferensi pengembang\\",\\"Jumlah fitur sistem\\",\\"Dampak terhadap pengalaman pengguna\\",\\"Kompleksitas kode\\"],\\"answer\\":\\"Dampak terhadap pengalaman pengguna\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Usability hanya berkaitan dengan teknologi, bukan perilaku manusia.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Think-Aloud Protocol dapat mengungkap masalah usability yang tidak terlihat dari observasi saja.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"True\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Heuristic Evaluation mengharuskan penggunaan pengguna nyata sebagai partisipan.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Heuristic Evaluation mengharuskan penggunaan pengguna nyata sebagai partisipan.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Remote usability testing harus selalu dilakukan secara real-time.\\",\\"options\\":[\\"True\\",\\"False\\"],\\"answer\\":\\"False\\",\\"type\\":\\"MC\\"},{\\"question\\":\\"Jelaskan mengapa usability testing penting dilakukan sebelum sistem diluncurkan secara luas!\\",\\"answer\\":\\"Usability testing penting karena membantu mengidentifikasi masalah penggunaan sejak dini sebelum berdampak pada kepuasan pengguna. Sistem dengan usability buruk berpotensi meningkatkan churn rate dan biaya dukungan pelanggan. Dengan melakukan pengujian lebih awal, pengembang dapat memperbaiki desain dan alur interaksi agar sistem lebih efisien, mudah digunakan, dan sesuai dengan kebutuhan pengguna nyata.\\",\\"type\\":\\"EY\\"},{\\"question\\":\\"Bandingkan Heuristic Evaluation dan Think-Aloud Protocol dari sisi pelaku evaluasi dan jenis data yang dihasilkan!\\",\\"answer\\":\\"Heuristic Evaluation dilakukan oleh evaluator ahli dengan mengacu pada prinsip usability Nielsen dan menghasilkan temuan berbasis aturan desain. Sementara itu, Think-Aloud Protocol melibatkan pengguna nyata yang diminta mengungkapkan proses berpikir mereka saat menggunakan sistem, sehingga menghasilkan data kualitatif berupa wawasan langsung tentang kebingungan, kesalahan, dan ekspektasi pengguna.\\",\\"type\\":\\"EY\\"},{\\"question\\":\\"Jelaskan peran analisis hasil evaluasi usability dalam peningkatan kualitas sistem!\\",\\"answer\\":\\"Analisis hasil evaluasi usability berperan sebagai dasar pengambilan keputusan perbaikan sistem. Data kualitatif digunakan untuk memahami pola masalah, sedangkan data kuantitatif mengukur tingkat keberhasilan sistem secara objektif. Dengan memprioritaskan perbaikan berdasarkan dampaknya terhadap pengalaman pengguna, sistem dapat dikembangkan secara iteratif dan lebih efektif dalam mencapai tujuannya.\\",\\"type\\":\\"EY\\"}]"	\N	2026-02-25 02:40:35.468	2026-02-25 03:22:01.833
